import React from 'react'
import TourCard from '../../shared/TourCard.jsx';
import tourData from '../../assets/data/tours'
import { Col,Row,Container  } from 'reactstrap';

const featuredTours=()=>{
  return (
    <>
    <section></section>
     <Container>
     <Row>
        {       
              tourData?.map(tour=>(
              <Col lg='3' className="mb-4" key={tour.id}>
                 <TourCard tour={tour}/>
                 </Col>
                
              ))
            
               }
             </Row>
             </Container>
             
    </>
  )
}

